(async function() {
  const datos = {"TECC055ESHK2": {"keywords": ["ELECTRICO", "COLGAR", "55"], "sku": "TECC055ESHK2", "fotos": ["data:image/jpeg;base64,", "data:image/jpeg;base64,"]}, "TECC085ESHK2": {"keywords": ["ELECTRICO", "COLGAR", "85"], "sku": "TECC085ESHK2", "fotos": ["data:image/jpeg;base64,", "data:image/jpeg;base64,"]}, "TEPC055ESHK2": {"keywords": ["ELECTRICO", "PIE", "55"], "sku": "TEPC055ESHK2", "fotos": ["data:image/jpeg;base64,", "data:image/jpeg;base64,", "data:image/jpeg;base64,"]}, "TEPC085ESHK2": {"keywords": ["ELECTRICO", "PIE", "85"], "sku": "TEPC085ESHK2", "fotos": ["data:image/jpeg;base64,", "data:image/jpeg;base64,"]}, "TPGP050MSH13": {"keywords": ["GAS", "PIE", "50"], "sku": "TPGP050MSH13", "fotos": ["data:image/jpeg;base64,", "data:image/jpeg;base64,"]}, "TPGP080MSH13": {"keywords": ["GAS", "PIE", "80"], "sku": "TPGP080MSH13", "fotos": ["data:image/jpeg;base64,", "data:image/jpeg;base64,"]}, "TPGP120MSH13": {"keywords": ["GAS", "PIE", "120"], "sku": "TPGP120MSH13", "fotos": ["data:image/jpeg;base64,", "data:image/jpeg;base64,"]}};

  // Cargar productos del storage
  let prods = JSON.parse(localStorage.getItem('rh_productos') || '[]');
  let actualizados = 0;

  for (const [sku, info] of Object.entries(datos)) {
    const kws = info.keywords.map(k => k.toUpperCase());
    const prod = prods.find(p => {
      const n = (p.nombre || '').toUpperCase();
      return kws.every(k => n.includes(k)) && (p.proveedor||'').toUpperCase().includes('RHEEM');
    });
    if (prod) {
      prod.fotos = info.fotos;
      prod.fotoPrincipal = 0;
      prod.codigoOriginal = prod.codigoOriginal || sku;
      actualizados++;
      console.log('✅ Actualizado:', prod.nombre);
    } else {
      console.warn('⚠️ No encontrado:', sku, kws);
    }
  }

  if (actualizados > 0) {
    localStorage.setItem('rh_productos', JSON.stringify(prods));
    // Sincronizar con la nube
    if (typeof syncCloud === 'function') {
      await syncCloud();
      console.log('☁️ Sincronizado con la nube');
    }
    alert('✅ ' + actualizados + ' productos Sherman actualizados con fotos. Recargá la página.');
  } else {
    alert('⚠️ No se encontraron productos Sherman. Verificá que estén importados.');
  }
})();
